# Thread management classes
class CancellableThread:
    def __init__(self, target_func, *args):
        self._target = target_func
        self._args = args
        self._cancelled = False
        self._thread = threading.Thread(target=self._run)
        self._process = None  # For subprocess cancellation
    
    def _run(self):
        try:
            self._target(*self._args)
        except Exception as e:
            if not self._cancelled:
                log_message('error', f"Thread error: {str(e)}")
    
    def start(self):
        self._thread.start()
        return self
    
    def cancel(self):
        self._cancelled = True
        # If there's a subprocess, terminate it
        if self._process and self._process.poll() is None:
            self._process.terminate()
    
    def join(self, timeout=None):
        return self._thread.join(timeout)
    
    def is_alive(self):
        return self._thread.is_alive()
    
    def set_process(self, process):
        """Set the subprocess for cancellation"""
        self._process = process

class ThreadManager:
    def __init__(self):
        self.active_threads = []
    
    def start_thread(self, target_func, *args):
        # Clean up finished threads
        self.cleanup_finished_threads()
        
        thread = CancellableThread(target_func, *args)
        thread.start()
        self.active_threads.append(thread)
        return thread
    
    def cleanup_finished_threads(self):
        self.active_threads = [t for t in self.active_threads if t.is_alive()]

# Initialize the thread manager
thread_manager = ThreadManager()

def log_message(level, message):
    """Log a message with timestamp"""
    if level == 'error':
        logging.error(message)
    elif level == 'warning':
        logging.warning(message)
    else:
        logging.info(message)

def validate_target(target):
    """Validate the target input"""
    if not target or not target.strip():
        return False, "Empty target provided"
    
    # Remove protocol if present
    if target.startswith('http://') or target.startswith('https://'):
        target = target.split('://', 1)[1]
    
    # Basic domain/IP validation
    domain_pattern = r'^(?:[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?\.)+[a-zA-Z]{2,}$'
    ip_pattern = r'^(?:[0-9]{1,3}\.){3}[0-9]{1,3}$'
    
    if not (re.match(domain_pattern, target) or re.match(ip_pattern, target)):
        return False, "Invalid domain or IP format"
    
    return True, target.strip()

