def update_results(gui_instance, text):
    """Thread-safe helper function to update the results text widget"""

    def _update():
        gui_instance.results.config(state=tk.NORMAL)
        gui_instance.results.delete(1.0, tk.END)
        gui_instance.results.insert(tk.END, text)
        gui_instance.results.config(state=tk.DISABLED)
        gui_instance.status_var.set("Ready")

    # Schedule the update to run in the main thread
    gui_instance.top.after(0, _update)


def append_results(gui_instance, text):
    """Thread-safe helper function to append text to the results text widget"""
    
    def _append():
        gui_instance.results.config(state=tk.NORMAL)
        gui_instance.results.insert(tk.END, text)
        
        # Limit the number of lines to prevent memory issues
        line_count = int(gui_instance.results.index('end-1c').split('.')[0])
        if line_count > MAX_LINES:
            # Remove the oldest lines
            delete_count = line_count - MAX_LINES
            gui_instance.results.delete(1.0, f"{delete_count}.0")
        
        gui_instance.results.see(tk.END)
        gui_instance.results.config(state=tk.DISABLED)

    # Schedule the update to run in the main thread
    gui_instance.top.after(0, _append)


def dumpster(target, gui_instance):
    update_results(gui_instance, 'DNS Dumpster (API Required) module running, please wait...')
    
    def _worker():
        # Validate input
        is_valid, clean_target = validate_target(target)
        if not is_valid:
            update_results(gui_instance, f'[+] Error: {clean_target}')
            return
        
        if dnsdumpsterapi == '':
            update_results(gui_instance, '[+] DNSdumpster API key missing, skipping test.')
            return

        try:
            url = f'https://api.dnsdumpster.com/domain/{clean_target}'
            headers = {'X-Api-Key': dnsdumpsterapi}
            
            # Add timeout to prevent hanging
            response = requests.get(url, headers=headers, timeout=30)
            
            if response.status_code == 200:
                try:
                    data = response.json()
                    
                    # Build the complete result text before updating the GUI
                    result_text = '\nA records:\n'
                    if 'a' in data and data['a']:
                        for item in data['a']:
                            result_text += '[+] Host:' + item['host'] + '\n'
                            for ip in item['ips']:
                                result_text += '[+] IP: ' + ip['ip'] + '\n'
                                result_text += '[+] ASN_NAME:' + ip['asn_name'] + '\n'
                                result_text += '[+] Country:' + ip['country'] + '\n'
                                result_text += '[+] City:' + ip.get('city', 'Not found') + '\n'
                                result_text += '-----------------------\n'
                    else:
                        result_text += 'No A records found.\n'
                    
                    result_text += '\nMX records:\n'
                    if 'mx' in data and data['mx']:
                        for item in data['mx']:
                            result_text += '[+] Host:' + item['host'] + '\n'
                            for ip in item['ips']:
                                result_text += '[+] IP: ' + ip['ip'] + '\n'
                                result_text += '[+] ASN_NAME:' + ip['asn_name'] + '\n'
                                result_text += '[+] Country:' + ip['country'] + '\n'
                                result_text += '[+] City:' + ip.get('city', 'Not found') + '\n'
                                result_text += '-----------------------\n'
                    else:
                        result_text += 'No MX records found.\n'
                    
                    result_text += '\nNS records:\n'
                    if 'ns' in data and data['ns']:
                        for item in data['ns']:
                            result_text += '[+] Host:' + item['host'] + '\n'
                            for ip in item['ips']:
                                result_text += '[+] IP: ' + ip['ip'] + '\n'
                                result_text += '[+] ASN_NAME:' + ip['asn_name'] + '\n'
                                result_text += '[+] Country:' + ip['country'] + '\n'
                                result_text += '[+] City:' + ip.get('city', 'Not found') + '\n'
                                result_text += '-----------------------\n'
                    else:
                        result_text += 'No NS records found.\n'
                    
                    # Update the GUI with the complete result
                    update_results(gui_instance, result_text)
                except ValueError as e:
                    update_results(gui_instance, f'[+] Error parsing JSON response: {str(e)}')
            elif response.status_code == 401:
                update_results(gui_instance, '[+] Error: Invalid API key for DNSdumpster')
            elif response.status_code == 429:
                update_results(gui_instance, '[+] Error: Rate limit exceeded for DNSdumpster API')
            else:
                update_results(gui_instance, f'[+] Error: HTTP {response.status_code} - {response.text}')
        except requests.exceptions.Timeout:
            update_results(gui_instance, '[+] Error: Request to DNSdumpster timed out')
        except requests.exceptions.ConnectionError:
            update_results(gui_instance, '[+] Error: Could not connect to DNSdumpster')
        except Exception as e:
            error_msg = f'Error in dumpster: {str(e)}'
            log_message('error', error_msg)
            update_results(gui_instance, f'[+] Unexpected error: {str(e)}')

    thread_manager.start_thread(_worker)


