def xsstest(target, gui_instance):
    update_results(gui_instance, 'XSS Detection module running, please wait...')
    
    def _worker():
        # Validate input
        is_valid, clean_target = validate_target(target)
        if not is_valid:
            update_results(gui_instance, f'[+] Error: {clean_target}')
            return
        
        try:
            url = f'https://www.{clean_target}/search?'
            payloads = ['<script>alert(1)</script>', '"><img src=x onerror=alert(1)>']
            result_text = ""
            for payload in payloads:
                params = {'q': payload}
                try:
                    r = requests.get(url, params=params, timeout=10)
                    if payload in r.text:
                        result_text += f'\n[XSS] Payload reflected: {payload}\n'
                    else:
                        result_text += f'\n[XSS] Not vulnerable to payload: {payload}\n'
                except requests.exceptions.RequestException as e:
                    result_text += f'\n[XSS] Error testing payload {payload}: {str(e)}\n'
            update_results(gui_instance, result_text)
        except Exception as e:
            error_msg = f'Error in xsstest: {str(e)}'
            log_message('error', error_msg)
            update_results(gui_instance, f'Error: {str(e)}')

    thread_manager.start_thread(_worker)


def run_subprocess_with_live_output(gui_instance, command, filename=None):
    """Run a subprocess command and display output in real-time"""
    process = None
    current_thread = threading.current_thread()
    
    try:
        # Start the subprocess
        process = subprocess.Popen(
            command,
            shell=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.STDOUT,
            universal_newlines=True,
            bufsize=1
        )
        
        # Store the process in the current thread for cancellation
        if hasattr(current_thread, 'set_process'):
            current_thread.set_process(process)
        
        # Read and display output line by line
        for line in iter(process.stdout.readline, ''):
            if line:  # Skip empty lines
                append_results(gui_instance, line.rstrip() + '\n')
        
        # Wait for the process to complete
        process.stdout.close()
        return_code = process.wait()
        
        if return_code != 0:
            append_results(gui_instance, f"\nCommand exited with code {return_code}\n")
        else:
            if filename:
                append_results(gui_instance, f"\nScan completed. Results saved to {filename}\n")
            else:
                append_results(gui_instance, "\nScan completed.\n")
                
    except Exception as e:
        append_results(gui_instance, f'Error: {str(e)}\n')
        error_msg = f'Error in subprocess: {str(e)}'
        log_message('error', error_msg)
    finally:
        # Ensure the process is terminated
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()


