def gobustertest(target, gui_instance):
    update_results(gui_instance, 'Gobuster module running, please wait...')
    
    def _worker():
        # Validate input
        is_valid, clean_target = validate_target(target)
        if not is_valid:
            update_results(gui_instance, f'[+] Error: {clean_target}')
            return
        
        # Create a dialog for wordlist input
        def get_wordlist():
            dialog = tk.Toplevel(gui_instance.top)
            dialog.title("Gobuster Configuration")
            dialog.geometry("400x150")
            dialog.configure(background="black")
            dialog.resizable(False, False)
            
            # Center the dialog
            dialog.transient(gui_instance.top)
            dialog.grab_set()
            
            tk.Label(dialog, text="Path to wordlist:", background="black", foreground="white").pack(pady=10)
            
            wordlist_entry = tk.Entry(dialog, width=50, bg="#2d2d2d", fg="white")
            wordlist_entry.pack(pady=5)
            
            result = {"path": None, "cancelled": False}
            
            def browse_wordlist():
                path = filedialog.askopenfilename(
                    title="Select Wordlist File",
                    filetypes=[("Text files", "*.txt"), ("All files", "*.*")]
                )
                if path:
                    wordlist_entry.delete(0, tk.END)
                    wordlist_entry.insert(0, path)
            
            def confirm():
                result["path"] = wordlist_entry.get()
                dialog.destroy()
            
            def cancel():
                result["cancelled"] = True
                dialog.destroy()
            
            tk.Button(dialog, text="Browse", command=browse_wordlist, bg="#2d2d2d", fg="white").pack(pady=5)
            
            button_frame = tk.Frame(dialog, bg="black")
            button_frame.pack(pady=10)
            
            tk.Button(button_frame, text="OK", command=confirm, bg="#2d2d2d", fg="white").pack(side=tk.LEFT, padx=10)
            tk.Button(button_frame, text="Cancel", command=cancel, bg="#2d2d2d", fg="white").pack(side=tk.RIGHT, padx=10)
            
            dialog.wait_window()
            return result
        
        wordlist_info = get_wordlist()
        if wordlist_info["cancelled"] or not wordlist_info["path"]:
            update_results(gui_instance, 'No wordlist provided, skipping test.')
            return
        
        path = wordlist_info["path"]
        filename = f'gobuster_results_{clean_target.replace("/", "_")}.txt'
        command = f'gobuster dir -u {clean_target} -w {path} -o {filename}'
        run_subprocess_with_live_output(gui_instance, command, filename)
    
    thread_manager.start_thread(_worker)


